  `payment_status` tinyint(4) NOT NULL DEFAULT 1,
  `payterm` int(11) DEFAULT NULL,
  `discount_percentage` decimal(11,0) DEFAULT NULL,
  `discount_amount` decimal(11,0) DEFAULT NULL,
  `total_amount` int(11) NOT NULL,
  `created_by` bigint(20) unsigned NOT NULL,
